func solve(n int64, edges [][]int64, label string) int64 {
    adj := make([][]int64, n)
    for _, e := range edges {
        u := e[0]
        v := e[1]
        adj[u] = append(adj[u], v)
        adj[v] = append(adj[v], u)
    }

    maxLen := int64(1)
    var dfs func(int64, uint64, string, *int64)
    dfs = func(current int64, visited uint64, path string, maxLen *int64) {
        if isPalindrome(path) {
            if len(path) > *maxLen {
                *maxLen = int64(len(path))
            }
        }
        for _, neighbor := range adj[current] {
            if (visited & (1 << neighbor)) != 0 {
                continue
            }
            newPath := path + string(label[neighbor])
            dfs(neighbor, visited | (1 << neighbor), newPath, maxLen)
        }
    }

    for start := 0; start < int(n); start++ {
        dfs(start, 1<<start, string(label[start]), &maxLen)
    }

    return maxLen
}

